import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './WelcomeScreen.css';

const WelcomeScreen = ({ language, onLanguageChange }) => {
  const navigate = useNavigate();
  const [currentQuoteIndex, setCurrentQuoteIndex] = useState(0);
  const [sessionId, setSessionId] = useState('');

  const languages = [
    { code: 'en', name: 'English', flag: '🇬🇧' },
    { code: 'hi', name: 'हिंदी', flag: '🇮🇳' },
    { code: 'ta', name: 'தமிழ்', flag: '🇮🇳' },
    { code: 'te', name: 'తెలుగు', flag: '🇮🇳' },
    { code: 'bn', name: 'বাংলা', flag: '🇮🇳' },
    { code: 'kn', name: 'ಕನ್ನಡ', flag: '🇮🇳' },
    { code: 'mr', name: 'मराठी', flag: '🇮🇳' }
  ];

  const content = {
    en: {
      title: 'Sahayak AI',
      subtitle: 'Your voice matters. Your safety matters. You are not alone.',
      quotes: [
        'Seeking help is a sign of strength.',
        'You are not alone.',
        'Your courage can change everything.',
        'Speaking up is the first step to healing.',
        'You deserve to feel safe.',
        'Every voice matters.'
      ],
      experienced: 'I experienced something',
      witnessed: 'I witnessed something',
      safeWordSetup: 'Set up Safe Word (Optional)',
      emergency: 'Emergency? Call 112'
    },
    hi: {
      title: 'सहायक AI',
      subtitle: 'आपकी आवाज़ मायने रखती है। आपकी सुरक्षा मायने रखती है। आप अकेले नहीं हैं।',
      quotes: [
        'मदद मांगना ताकत का संकेत है।',
        'आप अकेले नहीं हैं।',
        'आपका साहस सब कुछ बदल सकता है।',
        'बोलना उपचार की दिशा में पहला कदम है।',
        'आप सुरक्षित महसूस करने के हकदार हैं।',
        'हर आवाज़ मायने रखती है।'
      ],
      experienced: 'मैंने कुछ अनुभव किया',
      witnessed: 'मैंने कुछ देखा',
      safeWordSetup: 'सुरक्षा शब्द सेट करें (वैकल्पिक)',
      emergency: 'आपातकाल? 112 पर कॉल करें'
    },
    ta: {
      title: 'சஹாயக் AI',
      subtitle: 'உங்கள் குரல் முக்கியம். உங்கள் பாதுகாப்பு முக்கியம். நீங்கள் தனியாக இல்லை.',
      quotes: [
        'உதவி கேட்பது வலிமையின் அறிகுறி.',
        'நீங்கள் தனியாக இல்லை.',
        'உங்கள் தைரியம் எல்லாவற்றையும் மாற்றும்.',
        'பேசுவது குணப்படுத்துவதற்கான முதல் படி.',
        'நீங்கள் பாதுகாப்பாக உணர தகுதியுடையவர்.',
        'ஒவ்வொரு குரலும் முக்கியம்.'
      ],
      experienced: 'நான் ஏதோ அனுபவித்தேன்',
      witnessed: 'நான் ஏதோ பார்த்தேன்',
      safeWordSetup: 'பாதுகாப்பு வார்த்தை அமைக்கவும் (விருப்பம்)',
      emergency: 'அவசரநிலை? 112 ஐ அழைக்கவும்'
    },
    te: {
      title: 'సహాయక్ AI',
      subtitle: 'మీ గొంతు ముఖ్యం. మీ భద్రత ముఖ్యం. మీరు ఒంటరిగా లేరు.',
      quotes: [
        'సహాయం అడగడం బలం యొక్క సంకేతం.',
        'మీరు ఒంటరిగా లేరు.',
        'మీ ధైర్యం అన్నింటినీ మార్చగలదు.',
        'మాట్లాడడం వైద్యానికి మొదటి అడుగు.',
        'మీరు సురక్షితంగా అనుభవించడానికి అర్హులు.',
        'ప్రతి గొంతు ముఖ్యం.'
      ],
      experienced: 'నేను ఏదో అనుభవించాను',
      witnessed: 'నేను ఏదో చూశాను',
      safeWordSetup: 'సేఫ్ వర్డ్ సెటప్ చేయండి (ఐచ్ఛికం)',
      emergency: 'అత్యవసరం? 112కి కాల్ చేయండి'
    },
    bn: {
      title: 'সহায়ক AI',
      subtitle: 'আপনার কণ্ঠস্বর গুরুত্বপূর্ণ। আপনার নিরাপত্তা গুরুত্বপূর্ণ। আপনি একা নন।',
      quotes: [
        'সাহায্য চাওয়া শক্তির লক্ষণ।',
        'আপনি একা নন।',
        'আপনার সাহস সবকিছু পরিবর্তন করতে পারে।',
        'কথা বলা নিরাময়ের প্রথম ধাপ।',
        'আপনি নিরাপদ বোধ করার যোগ্য।',
        'প্রতিটি কণ্ঠস্বর গুরুত্বপূর্ণ।'
      ],
      experienced: 'আমি কিছু অনুভব করেছি',
      witnessed: 'আমি কিছু দেখেছি',
      safeWordSetup: 'নিরাপদ শব্দ সেট করুন (ঐচ্ছিক)',
      emergency: 'জরুরি? 112 এ কল করুন'
    },
    kn: {
      title: 'ಸಹಾಯಕ್ AI',
      subtitle: 'ನಿಮ್ಮ ಧ್ವನಿ ಮುಖ್ಯ. ನಿಮ್ಮ ಸುರಕ್ಷತೆ ಮುಖ್ಯ. ನೀವು ಒಬ್ಬಂಟಿಗರಲ್ಲ.',
      quotes: [
        'ಸಹಾಯ ಕೇಳುವುದು ಶಕ್ತಿಯ ಸಂಕೇತ.',
        'ನೀವು ಒಬ್ಬಂಟಿಗರಲ್ಲ.',
        'ನಿಮ್ಮ ಧೈರ್ಯ ಎಲ್ಲವನ್ನೂ ಬದಲಾಯಿಸಬಹುದು.',
        'ಮಾತನಾಡುವುದು ಗುಣಪಡಿಸುವ ಮೊದಲ ಹೆಜ್ಜೆ.',
        'ನೀವು ಸುರಕ್ಷಿತವಾಗಿ ಭಾವಿಸಲು ಅರ್ಹರು.',
        'ಪ್ರತಿ ಧ್ವನಿ ಮುಖ್ಯ.'
      ],
      experienced: 'ನಾನು ಏನನ್ನಾದರೂ ಅನುಭವಿಸಿದೆ',
      witnessed: 'ನಾನು ಏನನ್ನಾದರೂ ನೋಡಿದೆ',
      safeWordSetup: 'ಸುರಕ್ಷಿತ ಪದವನ್ನು ಹೊಂದಿಸಿ (ಐಚ್ಛಿಕ)',
      emergency: 'ತುರ್ತುಸ್ಥಿತಿ? 112 ಗೆ ಕರೆ ಮಾಡಿ'
    },
    mr: {
      title: 'सहायक AI',
      subtitle: 'तुमचा आवाज महत्त्वाचा आहे। तुमची सुरक्षा महत्त्वाची आहे। तुम्ही एकटे नाही आहात।',
      quotes: [
        'मदत मागणे हे शक्तीचे लक्षण आहे।',
        'तुम्ही एकटे नाही आहात।',
        'तुमचे धैर्य सर्वकाही बदलू शकते।',
        'बोलणे हे बरे होण्याची पहिली पायरी आहे।',
        'तुम्ही सुरक्षित वाटण्यास पात्र आहात।',
        'प्रत्येक आवाज महत्त्वाचा आहे।'
      ],
      experienced: 'मी काहीतरी अनुभवले',
      witnessed: 'मी काहीतरी पाहिले',
      safeWordSetup: 'सुरक्षित शब्द सेट करा (पर्यायी)',
      emergency: 'आणीबाणी? 112 वर कॉल करा'
    }
  };

  const text = content[language] || content.en;

  // Generate unique session ID on component mount
  useEffect(() => {
    const generateSessionId = () => {
      const year = new Date().getFullYear();
      const randomNum = Math.floor(Math.random() * 10000).toString().padStart(4, '0');
      return `SAH-${year}-${randomNum}`;
    };
    setSessionId(generateSessionId());
  }, []);

  // Rotate quotes every 4 seconds
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentQuoteIndex((prevIndex) => 
        (prevIndex + 1) % text.quotes.length
      );
    }, 4000);

    return () => clearInterval(interval);
  }, [text.quotes.length]);

  const handleEntryPoint = (type) => {
    // Store session ID and entry type in localStorage
    localStorage.setItem('sahayak_session_id', sessionId);
    localStorage.setItem('sahayak_entry_type', type);
    
    // Navigate to chat page with entry type
    navigate('/chat', { state: { entryType: type, sessionId } });
  };

  const handleSafeWordSetup = () => {
    navigate('/safe-word-setup');
  };

  return (
    <div className="landing-page">
      {/* Language Toggle Bar */}
      <div className="language-bar">
        {languages.map((lang) => (
          <button 
            key={lang.code}
            className={`lang-toggle ${language === lang.code ? 'active' : ''}`}
            onClick={() => onLanguageChange(lang.code)}
          >
            <span className="flag">{lang.flag}</span>
            {lang.name}
          </button>
        ))}
      </div>

      <div className="landing-content">
        <div className="main-section">
          <h1 className="app-title">{text.title}</h1>
          <p className="app-subtitle">{text.subtitle}</p>

          {/* Entry Point Buttons */}
          <div className="entry-buttons">
            <button 
              className="entry-btn experienced"
              onClick={() => handleEntryPoint('experienced')}
            >
              {text.experienced}
            </button>
            <button 
              className="entry-btn witnessed"
              onClick={() => handleEntryPoint('witnessed')}
            >
              {text.witnessed}
            </button>
          </div>

          {/* Rotating Motivational Quote */}
          <div className="quote-section">
            <p className="rotating-quote">
              {text.quotes[currentQuoteIndex]}
            </p>
          </div>

          {/* Safe Word Setup Link */}
          <div className="safe-word-section">
            <button 
              className="safe-word-link"
              onClick={handleSafeWordSetup}
            >
              {text.safeWordSetup}
            </button>
          </div>

          {/* Emergency Notice */}
          <div className="emergency-notice">
            <span className="emergency-icon">⚠️</span>
            {text.emergency}
          </div>
        </div>
      </div>
    </div>
  );
};

export default WelcomeScreen;
